/// Number of hand-crafted dialects (0–11) whose display strings we preserve as-is.
const HAND_CRAFTED_COUNT: u8 = 12;

/// Check whether an index is in the expansion range.
fn is_expansion(u: u8) -> bool {
    u >= HAND_CRAFTED_COUNT && (u as usize) < UNIVERSE_COUNT
}

/// Check whether an index is out of range entirely.
fn is_out_of_range(u: u8) -> bool {
    (u as usize) >= UNIVERSE_COUNT
}

/// Format a u8 as Unicode subscript digits (U+2080..U+2089).
fn subscript_u8(u: u8) -> String {
    if u == 0 {
        return "\u{2080}".to_string();
    }
    let mut buf = [0u8; 3]; // max two-digit decimal
    let mut n = u;
    let mut pos = 0;
    while n > 0 {
        buf[pos] = n % 10;
        n /= 10;
        pos += 1;
    }
    let mut out = String::new();
    for i in (0..pos).rev() {
        let digit = buf[i];
        out.push(char::from_u32(0x2080u32 + digit as u32).unwrap());
    }
    out
}

