/// Return the display name for a dialect index (Unicode subscript).
/// For U₀–U₁₁: hand-crafted. For U₁₂–U₈₇: generated from universe data.
pub fn dialect_display(u: u8) -> String {
    if is_out_of_range(u) {
        return "U?".to_string();
    }
    format!("U{}", subscript_u8(u))
}

/// Return the ASCII-safe name: "U_0" through "U_87".
pub fn dialect_ascii(u: u8) -> String {
    if is_out_of_range(u) {
        return "U_?".to_string();
    }
    format!("U_{}", u)
}

/// Return the canonical name for a dialect.
pub fn dialect_name(u: u8) -> &'static str {
    match u {
        0 => "canonical",
        1 => "low_gate",
        2 => "strict_frobenius",
        3 => "inverted_gates",
        4 => "no_ordering",
        5 => "high_gate",
        6 => "winding_first",
        7 => "t_structural",
        8 => "chirality_first",
        9 => "scope_dialect",
        10 => "triple_criticality",
        11 => "triple_criticality_gapped",
        _ if is_expansion(u) => {
            let unis = all_universes();
            unis[u as usize].name
        }
        _ => "unknown",
    }
}

