// DYNAMIC GATE EVALUATION (for expansion universes)
// ═══════════════════════════════════════════════════════════════

use crate::imas_ig::{IgPrim, IgTuple};

/// Map a GateSpec primitive string to the corresponding IgPrim value from an IgTuple.
/// Returns None for unrecognized primitive names.
pub fn prim_from_name(name: &str, ig: &IgTuple) -> Option<IgPrim> {
    match name {
        "Φ" => Some(ig.p),
        "⊙" => Some(ig.phi),
        "Ω" => Some(ig.omega),
        "Ħ" => Some(ig.h),
        "Γ" => Some(ig.g),
        "Þ" => Some(ig.t),
        "Ř" => Some(ig.r),
        "ƒ" => Some(ig.f),
        "Ç" => Some(ig.k),
        "Ð" => Some(ig.d),
        "Σ" => Some(ig.s),
        "ɢ" => Some(ig.c),
        _ => None,
    }
}

/// Evaluate a single gate spec against an IG tuple.
/// Returns (pass, prim_value_ordinal, prim_name).
pub fn eval_gate_spec(
    spec: &crate::universe_expansion::GateSpec,
    ig: &IgTuple,
) -> (bool, f32, &'static str) {
    let prim = prim_from_name(spec.prim, ig);
    match prim {
        Some(pv) => {
            let ord = pv.ordinal();
            (ord >= spec.min_ord, ord, pv.glyph())
        }
        None => (false, 0.0, "?"),
    }
}

/// Return the display name for a primitive family from a GateSpec prim string.
/// Used for verify output labels.
pub fn gate_prim_label(prim: &str) -> &'static str {
    match prim {
        "Φ" => "Φ",
        "⊙" => "φ̂",
        "Ω" => "Ω",
        "Ħ" => "Ħ",
        "Γ" => "Γ",
        "Þ" => "Þ",
        "Ř" => "Ř",
        "ƒ" => "ƒ",
        "Ç" => "Ç",
        "Ð" => "Ð",
        "Σ" => "Σ",
        "ɢ" => "ɢ",
        _ => "?",
    }
}

/// Whether a universe is hand-crafted and uses hardcoded gate logic in main.rs.
pub fn is_hand_crafted(u: u8) -> bool {
    u < HAND_CRAFTED_COUNT
}

/// The maximum valid dialect index (inclusive).
pub fn max_dialect() -> u8 {
    (UNIVERSE_COUNT - 1) as u8
}
